<?php $title='Videos';require __DIR__.'/partials/header.php';?><div class="row g-4"><div class="col-lg-5"><div class="card mb-3"><div class="card-body"><h1 class="h4">Upload video</h1><form method="post" action="/videos/upload" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input class="form-control mb-3" type="file" name="video" accept="video/*" required><button class="btn btn-primary">Upload</button></form></div></div><div class="card"><div class="card-body"><h2 class="h5">Import from YouTube</h2><form method="post" action="/videos/import"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input class="form-control mb-3" type="url" name="url" placeholder="https://www.youtube.com/watch?v=..." required><button class="btn btn-outline-primary">Queue import</button></form><p class="small text-secondary mt-3 mb-0">The worker downloads the video in the background.</p></div></div></div><div class="col-lg-7"><h1 class="h4">Library</h1><div class="list-group mb-4"><?php foreach($videos as $v):?><div class="list-group-item d-flex justify-content-between"><span><?=e($v['title'])?></span><span class="text-secondary small"><?=number_format((int)$v['size_bytes']/1048576,1)?> MB</span></div><?php endforeach?></div><h2 class="h5">Recent imports</h2><div class="list-group"><?php foreach($imports as $job):?><div class="list-group-item d-flex justify-content-between"><span class="text-truncate me-2"><?=e($job['source_url'])?></span><span class="badge text-bg-secondary"><?=e($job['status'])?></span></div><?php endforeach?></div></div></div><?php require __DIR__.'/partials/footer.php'; ?>
